        // Buffers: input row (innerSize floats), accumulator (innerSize floats), output row (innerSize floats)
        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, innerSize_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, innerSize_ * sizeof(float));
        pipe_.InitBuffer(tmpAccQueue_, 1, innerSize_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalOutputElems_ == 0 || tileLen_ == 0) return;

        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Grid stride over outer indices
        for (uint32_t outerIdx = blockIdx; outerIdx < outerSize_; outerIdx += blockNum) {
            // Process one outer index at a time, tiling inner dimension
            uint32_t baseOut = outerIdx * innerSize_;  // output start for this outer index
            uint32_t baseIn = outerIdx * outerStride_; // input offset for outerIdx, r=0, i=0
            // Tile over inner dimension
            for (uint32_t iStart = 0; iStart < innerSize_; iStart += tileLen_) {
                uint32_t curTile = innerSize_ - iStart;
                if (curTile > tileLen_) curTile = tileLen_;

                // Prefetch first reduce row
                prefetchInput(baseIn + iStart, curTile, 0);
                // Accumulate over reduce dimension
                for (uint32_t r = 0; r < reduceSize_; r++) {
                    if (r > 0) {
                        prefetchInput(baseIn + iStart, curTile, r);
                    }
                    accumulateAccumulator(curTile, r);
                }
                // Write output
                writeOutput(baseOut + iStart, curTile);
            }
        }
